class Solution:
    def lengthOfLIS(self, nums):
        # Independent O(n^2) dynamic program: dp[i] is the LIS ending at i.
        n = len(nums)
        dp = [1] * n
        for i in range(n):
            for j in range(i):
                if nums[j] < nums[i] and dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1
        return max(dp) if dp else 0

